previewCss:
.darma-loader-darma-custom-154 {
  color: var(--loader-color, #e11d48);
width: 45px;
height: 20px;
--c:no-repeat radial-gradient(farthest-side,currentColor 93%,#0000);
background:
var(--c) 0 0,
var(--c) 50% 0,
var(--c) 100% 0;
background-size: 8px 8px;
position: relative;
animation: darma-loader-darma-custom-154-l4-0 1s linear infinite alternate;
}
.darma-loader-darma-custom-154:before {
content: "";
position: absolute;
width: 8px;
height: 12px;
background: currentColor;
left: 0;
top: 0;
animation:
darma-loader-darma-custom-154-l4-1 1s linear infinite alternate,
darma-loader-darma-custom-154-l4-2 0.5s cubic-bezier(0,200,.8,200) infinite;
}
@keyframes darma-loader-darma-custom-154-l4-0 {
0% {background-position: 0 100%,50% 0 ,100% 0}
8%,42% {background-position: 0 0 ,50% 0 ,100% 0}
50% {background-position: 0 0 ,50% 100%,100% 0}
58%,92% {background-position: 0 0 ,50% 0 ,100% 0}
100% {background-position: 0 0 ,50% 0 ,100% 100%}
}
@keyframes darma-loader-darma-custom-154-l4-1 {
100% {left:calc(100% - 8px)}
}
@keyframes darma-loader-darma-custom-154-l4-2 {
100% {top:-0.1px}
}

